import org.springframework.web.client.RestTemplate;

import java.net.InetAddress;
import java.net.URL;
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;

/**
 * Service for fetching web page content.
 * Provides secure URL fetching with SSRF protection.
 */
@Service
public class WebPageFetcherService {

    private final RestTemplate restTemplate;
    private static final Set<String> ALLOWED_PROTOCOLS = 
            new HashSet<>(Arrays.asList("http", "https"));

    public WebPageFetcherService() {
        this.restTemplate = createRestTemplate();
    }

    /**
     * Creates a RestTemplate instance with security restrictions.
     * @return RestTemplate with disabled auto-redirects
     */
    private RestTemplate createRestTemplate() {
        ClientHttpRequestFactory factory = new SimpleClientHttpRequestFactory() {
            @Override
            protected void prepareConnection(java.net.HttpURLConnection connection,
                                             String httpMethod) throws java.io.IOException {
                super.prepareConnection(connection, httpMethod);
                connection.setInstanceFollowRedirects(false);
            }
        };
        return new RestTemplate(factory);
    }

    /**
     * Fetches the HTML content from the specified URL.
     * @param url the URL to fetch content from
     * @return the HTML content as a string
     * @throws IllegalArgumentException if URL is invalid or SSRF protection is triggered
     * @throws RuntimeException if HTTP request fails
     */
    public String getPageContent(String url) {
        if (!isSafeUrl(url)) {
            throw new IllegalArgumentException("URL blocked for security reasons");
        }

        try {
            return restTemplate.getForObject(url, String.class);
        } catch (Exception e) {
            throw new RuntimeException("Failed to fetch content from URL: " + url, e);
        }
    }

    /**
     * Validates that the URL is safe to request.
     * @param urlString the URL to validate
     * @return true if the URL is safe, false otherwise
     */
    private boolean isSafeUrl(String urlString) {
        if (urlString == null || urlString.trim().isEmpty()) {
            return false;
        }

        try {
            URL url = new URL(urlString);

            // Check protocol
            if (!ALLOWED_PROTOCOLS.contains(url.getProtocol().toLowerCase())) {
                return false;
            }

            // Check hostname
            String host = url.getHost();
            if (host == null || host.isEmpty()) {
                return false;
            }

            // Check for local addresses
            return !isLocalAddress(host);

        } catch (Exception e) {
            return false;
        }
    }

    /**
     * Checks if the host resolves to a local or private IP address.
     * @param host the hostname to check
     * @return true if the host resolves to a local address, false otherwise
     */
    private boolean isLocalAddress(String host) {
        try {
            InetAddress[] addresses = InetAddress.getAllByName(host);
            for (InetAddress addr : addresses) {
                if (addr.isAnyLocalAddress() ||
                    addr.isLoopbackAddress() ||
                    addr.isLinkLocalAddress() ||
                    addr.isSiteLocalAddress()) {
                    return true;
                }
            }
            return false;
        } catch (Exception e) {
            return true;
        }
    }
}

